**useValue** — Provide constant value:
```ts
// Constants, configs, mock objects
const configProvider = {
  provide: 'CONFIG',
  useValue: {
    apiUrl: 'https://api.example.com',
    timeout: 5000,
  },
};

@Injectable()
export class ApiService {
  constructor(@Inject('CONFIG') private config: Config) {}
}
```

**useClass** — Provide different implementation:
```ts
// Swap implementations based on environment
const loggerProvider = {
  provide: LoggerService,
  useClass:
    process.env.NODE_ENV === 'production'
      ? ProductionLoggerService
      : DevelopmentLoggerService,
};

// Mock for testing
const mockProvider = {
  provide: UserService,
  useClass: MockUserService,
};
```

**useFactory** — Dynamic creation with dependencies:
```ts
const databaseProvider = {
  provide: 'DATABASE_CONNECTION',
  useFactory: async (configService: ConfigService) => {
    const connection = await createConnection({
      host: configService.get('DB_HOST'),
      port: configService.get('DB_PORT'),
    });
    return connection;
  },
  inject: [ConfigService],
};

// Async factory
const asyncProvider = {
  provide: 'ASYNC_SERVICE',
  useFactory: async () => {
    const data = await fetchRemoteConfig();
    return new ConfiguredService(data);
  },
};
```

**useExisting** — Alias to existing provider:
```ts
// Create alias
const aliasProvider = {
  provide: 'AliasedLogger',
  useExisting: LoggerService,
};

// Both inject same instance
constructor(
  private logger: LoggerService,
  @Inject('AliasedLogger') private aliasedLogger: LoggerService,
) {
  console.log(logger === aliasedLogger); // true
}
```

**Summary**:
| Type | Use Case |
|------|----------|
| useValue | Static values, configs |
| useClass | Swap implementations |
| useFactory | Async init, dependencies |
| useExisting | Aliases, backwards compat |

